(function (global) {
  const ns = (global.AppBackend = global.AppBackend || {});
  const state = {
    roles: [],
    categories: [],
    productById: new Map(),
    specById: new Map(),
    mediaById: new Map(),
    activeProductId: "",
    activeProductSlug: "",
    activeProductName: "",
  };
  function text(id) {
    const el = document.getElementById(id);
    if (!el) return "";
    return (el.value || "").trim();
  }
  function checked(id) {
    const el = document.getElementById(id);
    return Boolean(el && el.checked);
  }
  function setStatus(message, isError) {
    const node = document.getElementById("admin-console-status");
    if (node) {
      node.textContent = message;
      node.className = isError ? "alert alert-danger" : "alert alert-info";
      node.style.display = "block";
    }
    if (ns.notify) {
      ns.notify(message, isError);
    }
  }
  function normalize(error, fallbackMessage) {
    if (ns.normalizeError) {
      return ns.normalizeError(error, fallbackMessage);
    }
    if (error && error.message) return error.message;
    return fallbackMessage || "Unexpected error";
  }
  function setText(selector, value) {
    const node = document.querySelector(selector);
    if (node) {
      node.textContent = value;
    }
  }
  function escapeHtml(value) {
    return String(value || "")
      .replace(/&/g, "&amp;")
      .replace(/</g, "&lt;")
      .replace(/>/g, "&gt;")
      .replace(/"/g, "&quot;")
      .replace(/'/g, "&#39;");
  }
  function formatDateTime(value) {
    if (!value) return "-";
    const parsed = new Date(value);
    if (Number.isNaN(parsed.getTime())) return "-";
    return parsed.toLocaleString("en-GB", {
      year: "numeric",
      month: "short",
      day: "2-digit",
      hour: "2-digit",
      minute: "2-digit",
    });
  }
  function toDateTimeLocal(value) {
    if (!value) return "";
    const parsed = new Date(value);
    if (Number.isNaN(parsed.getTime())) return "";
    const local = new Date(parsed.getTime() - parsed.getTimezoneOffset() * 60000);
    return local.toISOString().slice(0, 16);
  }
  function fromDateTimeLocal(value) {
    if (!value) return null;
    const parsed = new Date(value);
    if (Number.isNaN(parsed.getTime())) return null;
    return parsed.toISOString();
  }
  function splitFlavorNotes(value) {
    return String(value || "")
      .split(",")
      .map(function (part) {
        return part.trim();
      })
      .filter(Boolean);
  }
  function parseInteger(value, fallbackValue) {
    const parsed = Number.parseInt(String(value || ""), 10);
    if (Number.isFinite(parsed)) return parsed;
    return fallbackValue;
  }
  function hasStaffAccess(roles) {
    const normalized = (roles || []).map(function (role) {
      return String(role || "").toLowerCase();
    });
    return normalized.indexOf("admin") >= 0 || normalized.indexOf("staff") >= 0;
  }
  function renderInquiries(items) {
    const tbody = document.getElementById("inquiry-table-body");
    if (!tbody) return;
    if (!items || items.length === 0) {
      tbody.innerHTML = '<tr><td colspan="7">No inquiries found.</td></tr>';
      return;
    }
    const rows = items.map(function (item) {
      return [
        "<tr>",
        "<td>" + escapeHtml(item.id) + "</td>",
        "<td>" + escapeHtml(item.request_number) + "</td>",
        "<td>" + escapeHtml(item.status) + "</td>",
        "<td>" + escapeHtml(item.company_name) + "</td>",
        "<td>" + escapeHtml(item.work_email) + "</td>",
        "<td>" + escapeHtml(item.created_at) + "</td>",
        "<td><button type=\"button\" class=\"btn btn-xs btn-default js-pick-inquiry\" data-id=\"" + escapeHtml(item.id) + "\">Use</button></td>",
        "</tr>",
      ].join("");
    });
    tbody.innerHTML = rows.join("");
  }
  function renderCategoryOptions() {
    const select = document.getElementById("product-category");
    if (!select) return;
    const currentValue = select.value || "";
    const options = ['<option value="">None</option>'].concat(
      state.categories.map(function (item) {
        return '<option value="' + escapeHtml(item.id) + '">' + escapeHtml(item.name) + "</option>";
      }),
    );
    select.innerHTML = options.join("");
    if (currentValue) {
      select.value = currentValue;
    }
  }
  function categoryDisplay(item) {
    const relation = Array.isArray(item.product_categories) ? item.product_categories[0] : item.product_categories;
    if (relation && relation.name) return relation.name;
    const category = state.categories.find(function (entry) {
      return entry.id === item.category_id;
    });
    return category ? category.name : "-";
  }
  function flagsDisplay(item) {
    const tags = [];
    if (item.is_featured) tags.push("Featured");
    if (item.is_popular) tags.push("Popular");
    if (item.is_new_arrival) tags.push("New");
    return tags.length ? tags.join(", ") : "-";
  }
  function renderProducts(items) {
    const tbody = document.getElementById("product-table-body");
    if (!tbody) return;
    state.productById = new Map();
    if (!items || items.length === 0) {
      tbody.innerHTML = '<tr><td colspan="7">No products found.</td></tr>';
      return;
    }
    const rows = items.map(function (item) {
      state.productById.set(item.id, item);
      return [
        "<tr>",
        "<td>" + escapeHtml(item.slug) + "</td>",
        "<td>" + escapeHtml(item.name) + "</td>",
        "<td>" + escapeHtml(categoryDisplay(item)) + "</td>",
        "<td>" + escapeHtml(item.status) + "</td>",
        "<td>" + escapeHtml(flagsDisplay(item)) + "</td>",
        "<td>" + escapeHtml(formatDateTime(item.updated_at)) + "</td>",
        "<td>",
        '<button type="button" class="btn btn-xs btn-default js-edit-product" data-id="' + escapeHtml(item.id) + '">Edit</button> ',
        '<button type="button" class="btn btn-xs btn-danger js-delete-product" data-id="' + escapeHtml(item.id) + '">Delete</button>',
        "</td>",
        "</tr>",
      ].join("");
    });
    tbody.innerHTML = rows.join("");
  }
  function renderSpecs(items) {
    const tbody = document.getElementById("spec-table-body");
    if (!tbody) return;
    state.specById = new Map();
    if (!state.activeProductId) {
      tbody.innerHTML = '<tr><td colspan="6">Select a product to manage specifications.</td></tr>';
      setText("#spec-count", "0");
      return;
    }
    if (!items || items.length === 0) {
      tbody.innerHTML = '<tr><td colspan="6">No specifications found.</td></tr>';
      setText("#spec-count", "0");
      return;
    }
    const rows = items.map(function (item) {
      state.specById.set(item.id, item);
      return [
        "<tr>",
        "<td>" + escapeHtml(item.spec_key) + "</td>",
        "<td>" + escapeHtml(item.spec_value) + "</td>",
        "<td>" + escapeHtml(item.unit || "") + "</td>",
        "<td>" + escapeHtml(item.sort_order) + "</td>",
        "<td>" + escapeHtml(formatDateTime(item.updated_at)) + "</td>",
        "<td>",
        '<button type="button" class="btn btn-xs btn-default js-edit-spec" data-id="' + escapeHtml(item.id) + '">Edit</button> ',
        '<button type="button" class="btn btn-xs btn-danger js-delete-spec" data-id="' + escapeHtml(item.id) + '">Delete</button>',
        "</td>",
        "</tr>",
      ].join("");
    });
    tbody.innerHTML = rows.join("");
    setText("#spec-count", String(items.length));
  }
  function resolveMediaPreview(item) {
    if (item.external_url) return item.external_url;
    if (!item.bucket_name || !item.storage_path || !ns.getSupabaseClient) return "";
    const client = ns.getSupabaseClient();
    if (!client || !client.storage || !client.storage.from) return "";
    const response = client.storage.from(item.bucket_name).getPublicUrl(item.storage_path);
    return (response && response.data && response.data.publicUrl) || "";
  }
  function renderMedia(items) {
    const tbody = document.getElementById("media-table-body");
    if (!tbody) return;
    state.mediaById = new Map();
    if (!state.activeProductId) {
      tbody.innerHTML = '<tr><td colspan="7">Select a product to manage media.</td></tr>';
      setText("#media-count", "0");
      return;
    }
    if (!items || items.length === 0) {
      tbody.innerHTML = '<tr><td colspan="7">No media assets found.</td></tr>';
      setText("#media-count", "0");
      return;
    }
    const rows = items.map(function (item) {
      state.mediaById.set(item.id, item);
      const previewUrl = resolveMediaPreview(item);
      const source = item.external_url
        ? item.external_url
        : (item.bucket_name && item.storage_path ? (item.bucket_name + "/" + item.storage_path) : "-");
      return [
        "<tr>",
        '<td>' + (previewUrl ? ('<a href="' + escapeHtml(previewUrl) + '" target="_blank" rel="noopener">Preview</a>') : "-") + "</td>",
        "<td>" + escapeHtml(source) + "</td>",
        "<td>" + (item.is_primary ? "yes" : "no") + "</td>",
        "<td>" + escapeHtml(item.display_order) + "</td>",
        "<td>" + escapeHtml(item.visibility) + "</td>",
        "<td>" + escapeHtml(formatDateTime(item.updated_at)) + "</td>",
        "<td>",
        '<button type="button" class="btn btn-xs btn-default js-edit-media" data-id="' + escapeHtml(item.id) + '">Edit</button> ',
        '<button type="button" class="btn btn-xs btn-danger js-delete-media" data-id="' + escapeHtml(item.id) + '">Delete</button>',
        "</td>",
        "</tr>",
      ].join("");
    });
    tbody.innerHTML = rows.join("");
    setText("#media-count", String(items.length));
  }
  function resetSpecForm() {
    const form = document.getElementById("spec-manager-form");
    if (form) {
      form.reset();
    }
    const idNode = document.getElementById("spec-id");
    if (idNode) idNode.value = "";
    const sortNode = document.getElementById("spec-sort-order");
    if (sortNode) sortNode.value = "0";
  }
  function resetMediaForm() {
    const form = document.getElementById("media-manager-form");
    if (form) {
      form.reset();
    }
    const idNode = document.getElementById("media-id");
    if (idNode) idNode.value = "";
    const bucketNode = document.getElementById("media-bucket-name");
    if (bucketNode) bucketNode.value = "product-images";
    const displayOrderNode = document.getElementById("media-display-order");
    if (displayOrderNode) displayOrderNode.value = "0";
    const visibilityNode = document.getElementById("media-visibility");
    if (visibilityNode) visibilityNode.value = "public";
  }
  function clearActiveProduct() {
    state.activeProductId = "";
    state.activeProductSlug = "";
    state.activeProductName = "";
    setText("#spec-active-product", "none selected");
    setText("#media-active-product", "none selected");
    renderSpecs([]);
    renderMedia([]);
    resetSpecForm();
    resetMediaForm();
  }
  function setActiveProduct(item) {
    if (!item || !item.id) {
      clearActiveProduct();
      return;
    }
    state.activeProductId = item.id;
    state.activeProductSlug = item.slug || "";
    state.activeProductName = item.name || item.slug || item.id;
    setText("#spec-active-product", state.activeProductName);
    setText("#media-active-product", state.activeProductName);
    resetSpecForm();
    resetMediaForm();
    void loadSpecifications();
    void loadMediaAssets();
  }
  function fillProductForm(item) {
    const relation = Array.isArray(item.product_categories) ? item.product_categories[0] : item.product_categories;
    const categoryId = item.category_id || (relation && relation.id) || "";
    const idNode = document.getElementById("product-id");
    if (idNode) idNode.value = item.id || "";
    const slugNode = document.getElementById("product-slug");
    if (slugNode) slugNode.value = item.slug || "";
    const nameNode = document.getElementById("product-name");
    if (nameNode) nameNode.value = item.name || "";
    const categoryNode = document.getElementById("product-category");
    if (categoryNode) categoryNode.value = categoryId;
    const statusNode = document.getElementById("product-status");
    if (statusNode) statusNode.value = item.status || "draft";
    const originNode = document.getElementById("product-origin-country");
    if (originNode) originNode.value = item.origin_country || "Cameroon";
    const flavorNode = document.getElementById("product-flavor-notes");
    if (flavorNode) flavorNode.value = Array.isArray(item.flavor_notes) ? item.flavor_notes.join(", ") : "";
    const publishedNode = document.getElementById("product-published-at");
    if (publishedNode) publishedNode.value = toDateTimeLocal(item.published_at);
    const shortDescriptionNode = document.getElementById("product-short-description");
    if (shortDescriptionNode) shortDescriptionNode.value = item.short_description || "";
    const descriptionNode = document.getElementById("product-description");
    if (descriptionNode) descriptionNode.value = item.description || "";
    const featuredNode = document.getElementById("product-is-featured");
    if (featuredNode) featuredNode.checked = Boolean(item.is_featured);
    const popularNode = document.getElementById("product-is-popular");
    if (popularNode) popularNode.checked = Boolean(item.is_popular);
    const newArrivalNode = document.getElementById("product-is-new-arrival");
    if (newArrivalNode) newArrivalNode.checked = Boolean(item.is_new_arrival);
    setActiveProduct(item);
  }
  function resetProductForm() {
    const form = document.getElementById("product-manager-form");
    if (!form) return;
    form.reset();
    const idNode = document.getElementById("product-id");
    if (idNode) idNode.value = "";
    const statusNode = document.getElementById("product-status");
    if (statusNode) statusNode.value = "draft";
    const originNode = document.getElementById("product-origin-country");
    if (originNode) originNode.value = "Cameroon";
    clearActiveProduct();
  }
  function collectProductPayload() {
    const slug = text("product-slug")
      .toLowerCase()
      .replace(/[^a-z0-9]+/g, "-")
      .replace(/^-+|-+$/g, "");
    const slugInput = document.getElementById("product-slug");
    if (slugInput) {
      slugInput.value = slug;
    }
    const status = text("product-status") || "draft";
    const publishedAt = fromDateTimeLocal(text("product-published-at"));
    return {
      category_id: text("product-category") || null,
      slug: slug,
      name: text("product-name"),
      short_description: text("product-short-description") || null,
      description: text("product-description") || null,
      origin_country: text("product-origin-country") || "Cameroon",
      flavor_notes: splitFlavorNotes(text("product-flavor-notes")),
      is_featured: checked("product-is-featured"),
      is_popular: checked("product-is-popular"),
      is_new_arrival: checked("product-is-new-arrival"),
      status: status,
      published_at: publishedAt || (status === "published" ? new Date().toISOString() : null),
      deleted_at: null,
    };
  }
  function collectSpecPayload() {
    return {
      product_id: state.activeProductId,
      spec_key: text("spec-key"),
      spec_value: text("spec-value"),
      unit: text("spec-unit") || null,
      sort_order: parseInteger(text("spec-sort-order"), 0),
    };
  }
  function collectMediaPayload(existing, uploadResult) {
    const externalUrlField = text("media-external-url");
    let bucketName = null;
    let storagePath = null;
    let externalUrl = null;
    if (uploadResult && uploadResult.storagePath) {
      bucketName = uploadResult.bucketName || "product-images";
      storagePath = uploadResult.storagePath;
      externalUrl = null;
    } else if (externalUrlField) {
      externalUrl = externalUrlField;
      bucketName = null;
      storagePath = null;
    } else if (existing && existing.storage_path) {
      bucketName = existing.bucket_name;
      storagePath = existing.storage_path;
      externalUrl = null;
    } else if (existing && existing.external_url) {
      externalUrl = existing.external_url;
      bucketName = null;
      storagePath = null;
    } else {
      throw new Error("Provide either an upload file or external URL.");
    }
    return {
      product_id: state.activeProductId,
      bucket_name: bucketName,
      storage_path: storagePath,
      external_url: externalUrl,
      alt_text: text("media-alt-text") || null,
      media_type: "image",
      visibility: text("media-visibility") || "public",
      is_primary: checked("media-is-primary"),
      display_order: parseInteger(text("media-display-order"), 0),
    };
  }
  async function loadInquiries() {
    if (!ns.inquiryApi) return;
    try {
      const result = await ns.inquiryApi.listMyInquiries({ page: 1, pageSize: 20 });
      renderInquiries(result.items || []);
      setText("#inquiry-count", String((result.items || []).length));
    } catch (error) {
      setStatus(normalize(error, "Failed to load inquiries"), true);
    }
  }
  async function loadProductCategories() {
    if (!ns.adminApi) return;
    try {
      state.categories = await ns.adminApi.listProductCategories();
      renderCategoryOptions();
    } catch (error) {
      setStatus(normalize(error, "Failed to load product categories"), true);
    }
  }
  async function loadProducts() {
    if (!ns.adminApi) return;
    try {
      const result = await ns.adminApi.listProducts({ page: 1, pageSize: 100, includeDeleted: false });
      renderProducts(result.items || []);
      setText("#product-count", String((result.items || []).length));
      if (state.activeProductId) {
        const active = state.productById.get(state.activeProductId);
        if (active) {
          setActiveProduct(active);
        } else {
          clearActiveProduct();
        }
      }
    } catch (error) {
      setStatus(normalize(error, "Failed to load products"), true);
    }
  }
  async function loadSpecifications() {
    if (!ns.adminApi) return;
    if (!state.activeProductId) {
      renderSpecs([]);
      return;
    }
    try {
      const items = await ns.adminApi.listProductSpecifications(state.activeProductId);
      renderSpecs(items);
    } catch (error) {
      setStatus(normalize(error, "Failed to load product specifications"), true);
    }
  }
  async function loadMediaAssets() {
    if (!ns.adminApi) return;
    if (!state.activeProductId) {
      renderMedia([]);
      return;
    }
    try {
      const items = await ns.adminApi.listProductMediaAssets(state.activeProductId);
      renderMedia(items);
    } catch (error) {
      setStatus(normalize(error, "Failed to load product media assets"), true);
    }
  }
  async function refreshIdentity() {
    const user = await ns.authApi.getUser().catch(function () {
      return null;
    });
    const roles = user
      ? await ns.authApi.getMyRoles(user).catch(function () {
          return [];
        })
      : [];
    state.roles = roles;
    setText("#console-user-email", user ? (user.email || "unknown") : "Not signed in");
    setText("#console-user-roles", roles.length ? roles.join(", ") : "none");
    const gate = document.getElementById("console-auth-gate");
    if (gate) {
      gate.style.display = user ? "none" : "block";
    }
    return {
      user: user,
      roles: roles,
    };
  }
  async function onStatusUpdateSubmit(event) {
    event.preventDefault();
    if (!ns.inquiryApi) return;
    const inquiryId = text("status-inquiry-id");
    const toStatus = text("status-target");
    const note = text("status-note");
    if (!inquiryId || !toStatus) {
      setStatus("Inquiry ID and target status are required.", true);
      return;
    }
    try {
      await ns.inquiryApi.updateInquiryStatus(inquiryId, toStatus, note);
      setStatus("Inquiry status updated successfully.", false);
      event.target.reset();
      await loadInquiries();
    } catch (error) {
      setStatus(normalize(error, "Failed to update inquiry status"), true);
    }
  }
  async function onUpsertListingSubmit(event) {
    event.preventDefault();
    if (!ns.adminApi) return;
    const payload = {
      productSlug: text("listing-product-slug"),
      listingCode: text("listing-code"),
      status: text("listing-status") || "active",
      availableQuantityMt: text("listing-qty"),
      minimumOrderMt: text("listing-min-order"),
      priceUsdPerMt: text("listing-price"),
      currency: text("listing-currency") || "USD",
      incoterm: text("listing-incoterm"),
      originPort: text("listing-origin-port"),
      destinationRegion: text("listing-destination-region"),
      harvestSeason: text("listing-harvest-season"),
      validUntil: text("listing-valid-until"),
    };
    if (!payload.productSlug || !payload.listingCode) {
      setStatus("Product slug and listing code are required.", true);
      return;
    }
    try {
      const response = await ns.adminApi.upsertListing(payload);
      setStatus("Listing upserted: " + (response.listingCode || response.listingId), false);
    } catch (error) {
      setStatus(normalize(error, "Failed to upsert listing"), true);
    }
  }
  async function onSignedUrlSubmit(event) {
    event.preventDefault();
    if (!ns.adminApi) return;
    const payload = {
      bucket: text("signed-url-bucket"),
      path: text("signed-url-path"),
      expiresIn: Number(text("signed-url-expiry") || "300"),
    };
    if (!payload.bucket || !payload.path) {
      setStatus("Bucket and path are required for signed URL.", true);
      return;
    }
    try {
      const response = await ns.adminApi.createSignedUrl(payload);
      const output = document.getElementById("signed-url-output");
      if (output) {
        output.value = response.signedUrl || "";
      }
      setStatus("Signed URL generated successfully.", false);
    } catch (error) {
      setStatus(normalize(error, "Failed to create signed URL"), true);
    }
  }
  async function onProductSaveSubmit(event) {
    event.preventDefault();
    if (!ns.adminApi) return;
    const productId = text("product-id");
    const payload = collectProductPayload();
    if (!payload.slug || !payload.name) {
      setStatus("Product slug and name are required.", true);
      return;
    }
    try {
      if (productId) {
        const updated = await ns.adminApi.updateProduct(productId, payload);
        setStatus("Product updated: " + (updated.slug || updated.id), false);
      } else {
        const created = await ns.adminApi.createProduct(payload);
        setStatus("Product created: " + (created.slug || created.id), false);
      }
      await loadProducts();
      const next = productId || "";
      if (next && state.productById.get(next)) {
        fillProductForm(state.productById.get(next));
      }
    } catch (error) {
      setStatus(normalize(error, "Failed to save product"), true);
    }
  }
  async function onProductTableClick(event) {
    const trigger = event.target && event.target.closest ? event.target.closest(".js-edit-product, .js-delete-product") : null;
    if (!trigger) return;
    const productId = trigger.getAttribute("data-id") || "";
    if (!productId) return;
    if (trigger.classList.contains("js-edit-product")) {
      const item = state.productById.get(productId);
      if (!item) {
        setStatus("Unable to load product into form.", true);
        return;
      }
      fillProductForm(item);
      setStatus("Editing product: " + (item.slug || item.id), false);
      return;
    }
    if (!trigger.classList.contains("js-delete-product")) return;
    const item = state.productById.get(productId);
    const label = item ? item.slug : productId;
    const confirmed = global.confirm('Delete product "' + label + '" from catalog?');
    if (!confirmed) return;
    try {
      await ns.adminApi.deleteProduct(productId);
      setStatus("Product deleted: " + label, false);
      if (state.activeProductId === productId) {
        resetProductForm();
      }
      await loadProducts();
    } catch (error) {
      setStatus(normalize(error, "Failed to delete product"), true);
    }
  }
  async function onSpecSaveSubmit(event) {
    event.preventDefault();
    if (!ns.adminApi) return;
    if (!state.activeProductId) {
      setStatus("Select a product before managing specifications.", true);
      return;
    }
    const payload = collectSpecPayload();
    if (!payload.spec_key || !payload.spec_value) {
      setStatus("Spec key and value are required.", true);
      return;
    }
    const specId = text("spec-id");
    try {
      if (specId) {
        await ns.adminApi.updateProductSpecification(specId, payload);
        setStatus("Specification updated.", false);
      } else {
        await ns.adminApi.createProductSpecification(payload);
        setStatus("Specification created.", false);
      }
      resetSpecForm();
      await loadSpecifications();
    } catch (error) {
      setStatus(normalize(error, "Failed to save specification"), true);
    }
  }
  async function onSpecTableClick(event) {
    const trigger = event.target && event.target.closest ? event.target.closest(".js-edit-spec, .js-delete-spec") : null;
    if (!trigger) return;
    const specificationId = trigger.getAttribute("data-id") || "";
    const item = state.specById.get(specificationId);
    if (!item) return;
    if (trigger.classList.contains("js-edit-spec")) {
      const idNode = document.getElementById("spec-id");
      if (idNode) idNode.value = item.id;
      const keyNode = document.getElementById("spec-key");
      if (keyNode) keyNode.value = item.spec_key || "";
      const valueNode = document.getElementById("spec-value");
      if (valueNode) valueNode.value = item.spec_value || "";
      const unitNode = document.getElementById("spec-unit");
      if (unitNode) unitNode.value = item.unit || "";
      const orderNode = document.getElementById("spec-sort-order");
      if (orderNode) orderNode.value = String(item.sort_order || 0);
      setStatus("Editing specification: " + item.spec_key, false);
      return;
    }
    const confirmed = global.confirm('Delete specification "' + (item.spec_key || item.id) + '"?');
    if (!confirmed) return;
    try {
      await ns.adminApi.deleteProductSpecification(item.id);
      setStatus("Specification deleted.", false);
      resetSpecForm();
      await loadSpecifications();
    } catch (error) {
      setStatus(normalize(error, "Failed to delete specification"), true);
    }
  }
  async function onMediaSaveSubmit(event) {
    event.preventDefault();
    if (!ns.adminApi) return;
    if (!state.activeProductId) {
      setStatus("Select a product before managing media.", true);
      return;
    }
    const mediaId = text("media-id");
    const existing = mediaId ? state.mediaById.get(mediaId) : null;
    const fileInput = document.getElementById("media-file-input");
    const file = fileInput && fileInput.files && fileInput.files.length ? fileInput.files[0] : null;
    try {
      let uploadResult = null;
      if (file) {
        uploadResult = await ns.adminApi.uploadProductImage({
          bucket: text("media-bucket-name") || "product-images",
          file: file,
          productSlug: state.activeProductSlug || "product",
        });
      }
      const payload = collectMediaPayload(existing, uploadResult);
      let saved = null;
      if (mediaId) {
        saved = await ns.adminApi.updateProductMediaAsset(mediaId, payload);
        setStatus("Media updated.", false);
      } else {
        saved = await ns.adminApi.createProductMediaAsset(payload);
        setStatus("Media created.", false);
      }
      if (payload.is_primary && saved && saved.id) {
        await ns.adminApi.setPrimaryProductMedia(state.activeProductId, saved.id);
      }
      resetMediaForm();
      await loadMediaAssets();
    } catch (error) {
      setStatus(normalize(error, "Failed to save media"), true);
    }
  }
  async function onMediaTableClick(event) {
    const trigger = event.target && event.target.closest ? event.target.closest(".js-edit-media, .js-delete-media") : null;
    if (!trigger) return;
    const mediaId = trigger.getAttribute("data-id") || "";
    const item = state.mediaById.get(mediaId);
    if (!item) return;
    if (trigger.classList.contains("js-edit-media")) {
      const idNode = document.getElementById("media-id");
      if (idNode) idNode.value = item.id;
      const bucketNode = document.getElementById("media-bucket-name");
      if (bucketNode) bucketNode.value = item.bucket_name || "product-images";
      const altNode = document.getElementById("media-alt-text");
      if (altNode) altNode.value = item.alt_text || "";
      const orderNode = document.getElementById("media-display-order");
      if (orderNode) orderNode.value = String(item.display_order || 0);
      const visibilityNode = document.getElementById("media-visibility");
      if (visibilityNode) visibilityNode.value = item.visibility || "public";
      const externalNode = document.getElementById("media-external-url");
      if (externalNode) externalNode.value = item.external_url || "";
      const primaryNode = document.getElementById("media-is-primary");
      if (primaryNode) primaryNode.checked = Boolean(item.is_primary);
      const fileNode = document.getElementById("media-file-input");
      if (fileNode) fileNode.value = "";
      setStatus("Editing media asset.", false);
      return;
    }
    let purgeStorageObject = false;
    if (item.storage_path && item.bucket_name) {
      purgeStorageObject = global.confirm("Delete the storage file too? Click OK for both file and record, Cancel for record only.");
    }
    const confirmed = global.confirm("Delete this media record?");
    if (!confirmed) return;
    try {
      await ns.adminApi.deleteProductMediaAsset(item.id, purgeStorageObject);
      setStatus("Media deleted.", false);
      resetMediaForm();
      await loadMediaAssets();
    } catch (error) {
      setStatus(normalize(error, "Failed to delete media"), true);
    }
  }
  function bindEvents() {
    const statusForm = document.getElementById("status-update-form");
    if (statusForm) {
      statusForm.addEventListener("submit", function (event) {
        void onStatusUpdateSubmit(event);
      });
    }
    const listingForm = document.getElementById("listing-upsert-form");
    if (listingForm) {
      listingForm.addEventListener("submit", function (event) {
        void onUpsertListingSubmit(event);
      });
    }
    const signedUrlForm = document.getElementById("signed-url-form");
    if (signedUrlForm) {
      signedUrlForm.addEventListener("submit", function (event) {
        void onSignedUrlSubmit(event);
      });
    }
    const refreshInquiriesBtn = document.getElementById("refresh-inquiries-btn");
    if (refreshInquiriesBtn) {
      refreshInquiriesBtn.addEventListener("click", function () {
        void loadInquiries();
      });
    }
    const inquiriesTable = document.getElementById("inquiry-table-body");
    if (inquiriesTable) {
      inquiriesTable.addEventListener("click", function (event) {
        const trigger = event.target && event.target.closest ? event.target.closest(".js-pick-inquiry") : null;
        if (!trigger) return;
        const inquiryId = trigger.getAttribute("data-id") || "";
        const input = document.getElementById("status-inquiry-id");
        if (input) {
          input.value = inquiryId;
        }
      });
    }
    const productForm = document.getElementById("product-manager-form");
    if (productForm) {
      productForm.addEventListener("submit", function (event) {
        void onProductSaveSubmit(event);
      });
    }
    const productTable = document.getElementById("product-table-body");
    if (productTable) {
      productTable.addEventListener("click", function (event) {
        void onProductTableClick(event);
      });
    }
    const refreshProductsBtn = document.getElementById("refresh-products-btn");
    if (refreshProductsBtn) {
      refreshProductsBtn.addEventListener("click", function () {
        void loadProducts();
      });
    }
    const clearProductBtn = document.getElementById("product-form-clear-btn");
    if (clearProductBtn) {
      clearProductBtn.addEventListener("click", function () {
        resetProductForm();
      });
    }
    const specForm = document.getElementById("spec-manager-form");
    if (specForm) {
      specForm.addEventListener("submit", function (event) {
        void onSpecSaveSubmit(event);
      });
    }
    const specsTable = document.getElementById("spec-table-body");
    if (specsTable) {
      specsTable.addEventListener("click", function (event) {
        void onSpecTableClick(event);
      });
    }
    const refreshSpecsBtn = document.getElementById("refresh-specs-btn");
    if (refreshSpecsBtn) {
      refreshSpecsBtn.addEventListener("click", function () {
        void loadSpecifications();
      });
    }
    const clearSpecBtn = document.getElementById("spec-form-clear-btn");
    if (clearSpecBtn) {
      clearSpecBtn.addEventListener("click", function () {
        resetSpecForm();
      });
    }
    const mediaForm = document.getElementById("media-manager-form");
    if (mediaForm) {
      mediaForm.addEventListener("submit", function (event) {
        void onMediaSaveSubmit(event);
      });
    }
    const mediaTable = document.getElementById("media-table-body");
    if (mediaTable) {
      mediaTable.addEventListener("click", function (event) {
        void onMediaTableClick(event);
      });
    }
    const refreshMediaBtn = document.getElementById("refresh-media-btn");
    if (refreshMediaBtn) {
      refreshMediaBtn.addEventListener("click", function () {
        void loadMediaAssets();
      });
    }
    const clearMediaBtn = document.getElementById("media-form-clear-btn");
    if (clearMediaBtn) {
      clearMediaBtn.addEventListener("click", function () {
        resetMediaForm();
      });
    }
  }
  async function init() {
    if (!ns.hasSupabaseConfig || !ns.hasSupabaseConfig()) {
      setStatus("Supabase config is missing. Update js/supabase/config.js.", true);
      return;
    }
    if (!ns.authApi || !ns.inquiryApi || !ns.adminApi) {
      setStatus("Required Supabase modules are not loaded.", true);
      return;
    }
    const identity = await refreshIdentity();
    if (!identity || !identity.user) {
      setStatus("Sign in with a staff or admin account to use the admin console.", true);
      return;
    }
    if (!hasStaffAccess(identity.roles)) {
      setStatus("Access denied: your account is not assigned a staff/admin role.", true);
      return;
    }
    await loadInquiries();
    await loadProductCategories();
    await loadProducts();
    bindEvents();
  }
  if (document.readyState === "loading") {
    document.addEventListener("DOMContentLoaded", function () {
      void init();
    }, { once: true });
  } else {
    void init();
  }
})(window);
